import React, { createContext, useContext, useEffect, useState } from 'react';
import { onAuthStateChanged } from 'firebase/auth';
import { auth } from '../firebase/config';
import { getPlayer } from '../firebase/services';
import { getDatabase, ref, get } from "firebase/database";

const AuthContext = createContext({});

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [playerData, setPlayerData] = useState(null);
  const [loading, setLoading] = useState(true);

const db = getDatabase();

useEffect(() => {
  const unsubscribe = onAuthStateChanged(auth, async (user) => {
    if (user) {
      const snapshot = await get(ref(db, "players/" + user.uid));
      const data = snapshot.val();

      if (data?.isAdmin) {
        navigate("/admin/setup");   // ✅ admin redirect
      } else {
        navigate("/dashboard");     // ✅ player redirect
      }
    }
  });

  return () => unsubscribe();
}, []);

  const refreshPlayerData = async () => {
    if (user) {
      const data = await getPlayer(user.uid);
      setPlayerData(data);
    }
  };

  return (
    <AuthContext.Provider value={{ user, playerData, loading, refreshPlayerData }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
